  UPDATE products SET description = 'O composto polidor de corte Alumina Cutmax é revolucionário, um verdadeiro produto One Step. Tremendo poder de corte e acabamento impecável, algo impensável para um produto destinado a corte. A capacidade de remoção rápida de riscos e nivelamento de texturas impressiona. É o primeiro composto de corte produzido para qualquer tipo de verniz, dos mais macios aos mais duros e complexos. Um único produto, em qualquer situação. Isso acontece pelo uso do exclusivo sistema EASY SIA de abrasivos inteligentes, formados em 5 tipos de grão atendendo desde repinturas, vernizes cerâmicos a vernizes extremamente macios. E o melhor, sem geração de pó. Alternativa rápida e de extrema qualidade para processos de polimento. Aplicação: • Qualquer tipo de verniz; Principais características: • Corte de marcas de lixa P1200; • Produto a base de água; • Lubrificação excelente; • Rápida remoção de riscos e texturas; • Acabamento impecável em uma só etapa; • Não gera pó; • Alto rendimento; • Exclusivo sistema de abrasivos inteligentes EASY SIA. Modo de usar: 1. Alumina Cutmax pode ser usado em máquinas rotativas e roto orbitais; 2. Coloque produto na boina de polimento e espalhe com a máquina desligada; 3. Com o produto espalhado na peça, inicie o processo de polimento; 4. Na fase inicial trabalhe com uma leve pressão e mais velocidade; 5. Diminua a pressão e a velocidade a medida que os abrasivos forem quebrando; 6. Remova da peça com um pano de microfibras e use IPA ETS para inspeção final.', short_description = 'Composto polidor de corte pesado. Remoção rápida de riscos e nivelamento de texturas.', usability = 'Alumina Cutmax pode ser usado em máquinas rotativas e roto orbitais. Coloque produto na boina de polimento e espalhe com a máquina desligada. Com o produto espalhado na peça, inicie o processo de polimento. Na fase inicial trabalhe com uma leve pressão e mais velocidade. Diminua a pressão e a velocidade a medida que os abrasivos forem quebrando. Remova da peça com um pano de microfibras e use IPA ETS para inspeção final.', specifications = '{"Tipo":"Composto Polidor","Corte":"Pesado","Marca":"EasyTech","Volume":"500ml"}'::jsonb WHERE id = '29d75a27-24c7-46fc-b9d6-d39ac9b48ee0';
  UPDATE products SET description = 'Sabemos que a cera de carnaúba é conhecida pelo brilho quente que proporciona à pintura. Com a evolução do mercado há crescente tendência para os produtos à base de polímeros e resinas sintéticas. A Easytech desenvolveu a Alumina Detailing, um composto de refino que alia o melhor dos dois mundos. A capacidade de refino e nivelamento de texturas impressiona, é o primeiro composto de refino produzido para qualquer tipo de verniz. Indicado para correção de defeitos médios na pintura.', short_description = 'Composto polidor de refino. Nivelamento de texturas e preparo para lustro.', usability = 'Alumina Detailing pode ser usado em máquinas rotativas e roto orbitais. Coloque produto na boina de polimento e espalhe com a máquina desligada. Com o produto espalhado na peça, inicie o processo de polimento.', specifications = '{"Tipo":"Composto Polidor","Corte":"Refino","Marca":"EasyTech","Volume":"500ml"}'::jsonb WHERE id = '6062980f-c286-462d-8dbb-5681fb8ee3ca';
  UPDATE products SET description = 'A capacidade de refino e nivelamento de texturas impressiona. É o primeiro composto de lustro produzido para qualquer tipo de verniz. Indicado para finalização de processos de polimento.', short_description = 'Composto polidor de lustro. Acabamento impecável e brilho intenso.', usability = 'Alumina Perfect Gloss pode ser usado em máquinas rotativas e roto orbitais. Coloque produto na boina de polimento e espalhe com a máquina desligada. Com o produto espalhado na peça, inicie o processo de polimento.', specifications = '{"Tipo":"Composto Polidor","Corte":"Lustro","Marca":"EasyTech","Volume":"500ml"}'::jsonb WHERE id = '0e6cd462-5bae-4cd1-8eda-2a389991cc70';
